import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authAPI } from '../../api/client';
import { useAuth } from '../../hooks/useAuth';
import { Input } from '../../components/common/Input';
import { subscribeToPush } from '../../utils/pushNotifications';
import { Button } from '../../components/common/Button';
import { formatPhone, normalizePhone, isPhoneComplete } from '../../utils/phone';
import styles from './LoginPage.module.css';

export default function LoginPage() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [phone, setPhone] = useState('');
  const [phoneRaw, setPhoneRaw] = useState('');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState({});
  const [apiError, setApiError] = useState('');
  const [loading, setLoading] = useState(false);

  function validate() {
    const e = {};
    if (!isPhoneComplete(phone)) e.phone = 'Введите корректный номер телефона';
    if (!password) e.password = 'Введите пароль';
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  async function handleSubmit() {
    if (!validate()) return;
    setLoading(true);
    setApiError('');
    try {
      const { data } = await authAPI.login(phoneRaw, password);
      login(data, data.role);
      subscribeToPush(client);
      if (data.role === 'admin') navigate('/admin');
      else navigate('/instructor');
    } catch (err) {
      const msg = err.response?.data?.detail;
      if (err.response?.status === 403) setApiError(msg || 'Аккаунт не активирован.');
      else setApiError(msg || 'Неверный номер телефона или пароль.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className={styles.page}>
      <div className={styles.card}>
        <div className={styles.logo}>
          <span className={styles.logoMain}>Экипаж</span>
          <span className={styles.logoSub}>автошкола</span>
        </div>

        <h2 className={styles.title}>Вход</h2>

        <div className={styles.form}>
          <Input
            label="Номер телефона"
            type="phone"
            value={phone}
            onChange={(formatted, raw) => { setPhone(formatted); setPhoneRaw(raw); }}
            placeholder="+7 (999) 000-00-00"
            error={errors.phone}
            autoComplete="tel"
          />
          <Input
            label="Пароль"
            type="password"
            value={password}
            onChange={setPassword}
            placeholder="••••••••"
            error={errors.password}
            autoComplete="current-password"
          />

          {apiError && <div className={styles.apiError}>{apiError}</div>}

          <Button
            fullWidth
            variant="primary"
            size="lg"
            loading={loading}
            onClick={handleSubmit}
          >
            Войти
          </Button>

          <div className={styles.links}>
            <Link to="/forgot-password" className={styles.link}>
              Забыли пароль?
            </Link>
            <Link to="/register" className={styles.link}>
              Регистрация
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}
